数组package Array;

import org.junit.Test;

/**
 * 自定义数组类
 */
public class Array&lt;T> &#123;
    private T[] data;
    private int size;
    public Array()&#123;
        this(10);
    &#125;
    private Array(int capacity)&#123;
        data = (T[]) new Object[capacity];
        size = 0;
    &#125;
    //返回数组中的元素个数
    public int getSize()&#123;
        return size;
    &#125;
    //返回数组的长度
    public int getCapacity()&#123;
        return data.length;
    &#125;
    //判断数组是否为空
    public boolean isEmpty()&#123;
        return size == 0;
    &#125;
    //向数组中指定位置添加元素
    public void add(int index,T t)&#123;
        if(index &lt; 0 || index > size)//下标合法性判断
            throw new IllegalArgumentException("插入元素失败，下标不合法。");
        if(size == data.length)//数组容量判断
            resize(data.length &lt;&lt; 1);
        //元素插入操作
        for (int i = size; i > index; i--) &#123;
            data[i] = data[i-1];
        &#125;
        data[index] = t;
        size++;
    &#125;
    private void resize(int newCapacity)&#123;//扩容和缩容操作
        T[] newData = (T[]) new Object[newCapacity];
        for (int i = 0 ;i &lt; size ;i ++)&#123;
            newData[i] = data[i];
        &#125;
        data = newData;
    &#125;
    //在末尾添加元素
    public void addLast(T t)&#123;
        add(size,t);
    &#125;
    //在开头添加元素
    public void addFirst(T t)&#123;
        add(0,t);
    &#125;
    //删除指定位置的元素
    public T remove(int index)&#123;
        if(index &lt; 0 || index >= size)//下标合法性判断
            throw new IllegalArgumentException("删除元素失败，下标不合法。");
        T removedElem = data[index];
        for (int i = index; i &lt; size-1 ; i++) &#123;
            data[i] = data[i+1];
        &#125;
        data[size] = null;
        size--;
        if(size == data.length /4 &amp;&amp; data.length /4 != 0)
            resize(data.length /2);//缩容避免震荡复杂度
        return removedElem;
    &#125;
    //删除末尾元素
    public T removeLast()&#123;
        return remove(size-1);
    &#125;
    //删除第一个元素
    public T removeFirst()&#123;
        return remove(0);
    &#125;
    //获取指定位置的元素
    public T get(int index)&#123;
        if(index &lt; 0 || index >= size)//下标合法性判断
            throw new IllegalArgumentException("获取元素失败，下标不合法。");
        return data[index];
    &#125;
    //修改指定位置的元素
    public void set(int index,T t)&#123;
        if(index &lt; 0 || index >= size)//下标合法性判断
            throw new IllegalArgumentException("修改元素失败，下标不合法。");
        data[index] = t;
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append(String.format("Array[size:%d  capacity:%d]\n",size,data.length));
        stringBuilder.append("[");
        for (int i = 0; i &lt; size; i++) &#123;
            if (i != size-1)
                stringBuilder.append(data[i] + ",");
        &#125;
        stringBuilder.append(data[size-1]+"]");
        return stringBuilder.toString();
    &#125;

    @Test
    public void test()&#123;
        Array&lt;Integer> arr = new Array&lt;Integer>();
        for (int i = 0; i &lt; 10; i++) &#123;
            arr.addLast(i);
        &#125;
        System.out.println(arr);
        arr.add(1,90);
        System.out.println(arr);
        arr.addFirst(30);
        System.out.println(arr);
        arr.remove(2);
        System.out.println(arr);
        arr.removeFirst();
        System.out.println(arr);
        System.out.println(arr.get(3));
        arr.set(5,100);
        System.out.println(arr);

    &#125;

&#125;

链表package datastructure.linkedlist;

/**
 * 链表的实现
 */
public class LinkedList&lt;T> &#123;

    private class Node&#123;//节点类
//        public 属性保证在类的外面可以访问，不写setter和getter方法
        public T t;//存储数据
        public Node next;//指向下一个节点
        public Node(T t,Node next)&#123;
            this.t = t;
            this.next = next;
        &#125;
        public Node(T t)&#123;
            this(t,null);
        &#125;
        public Node()&#123;
            this(null,null);
        &#125;

        @Override
        public String toString() &#123;
            return t.toString();
        &#125;
    &#125;
    //使用虚拟头结点方便添加和删除
    private Node dummyHead;//表示第一个元素的前一个元素
    private int size;//记录元素个数
    public LinkedList()&#123;
        dummyHead = new Node(null,null);
        size = 0;
    &#125;

    public int getSize()&#123;
        return size;
    &#125;
    public boolean isEmpty()&#123;
        return size == 0;
    &#125;
    //向链表的指定索引位置中添加元素
    public void add(int index,T t)&#123;
        if(index &lt; 0 || index > size)
            throw new IllegalArgumentException("添加元素失败，下标不合法。");
        //找到要删除元素的前一个元素
        Node prev = dummyHead;
        for (int i = 0; i &lt; index; i++) &#123;
            prev = prev.next;
        &#125;
        //添加元素过程
        //1.新元素的next指向pre的next
        //2.pre.next指向新元素
        prev.next = new Node(t,prev.next);
        size++;
    &#125;
    //在链表的头部插入元素
    public void addFirst(T t)&#123;
        add(0,t);
    &#125;
    //在链表的末尾插入元素
    public void addLast(T t)&#123;
        add(size,t);
    &#125;
    //删除指定索引位置的元素
    public T remove(int index)&#123;
        if(index &lt; 0 || index >= size)
            throw new IllegalArgumentException("删除元素失败，索引不合法。");
        Node prev = dummyHead;
        for (int i = 0; i &lt; index; i++) &#123;
            prev = prev.next;//下移到要删除元素的前一个元素
        &#125;
        Node retNode = prev.next;//保存返回值
        prev.next = retNode.next;
        retNode.next = null;
        size--;
        return retNode.t;
    &#125;
    //删除链表头部元素
    public T removeFitrst()&#123;
        return remove(0);
    &#125;
    //删除链表末尾的元素
    public T removeLast()&#123;
        return remove(size-1);
    &#125;
    //获取指定位置的元素
    public T get(int index)&#123;
        if(index &lt; 0 || index >= size)
            throw new IllegalArgumentException("元素获取失败，索引不合法。");
        Node cur = dummyHead.next;
        for (int i = 0; i &lt; index; i++) &#123;
            cur = cur.next;
        &#125;
        return cur.t;
    &#125;
    //获取链表头部元素
    public T getFirst()&#123;
        return get(0);
    &#125;
    //获取链表尾部的元素
    public T getLast()&#123;
        return get(size-1);
    &#125;
    //判断是否包含某个元素
    public boolean contains(T t)&#123;
        Node cur = dummyHead.next;
        while(cur != null)&#123;
            if(cur.t.equals(t))
                return true;
            cur = cur.next;
        &#125;
        return false;
    &#125;
    //修改指定位置的元素
    public void set(int index,T t)&#123;
        if(index &lt; 0 || index >= size)
            throw new IllegalArgumentException("修改元素失败，索引不合法。");
        Node cur = dummyHead.next;
        for (int i = 0; i &lt; index; i++) &#123;
            cur = cur.next;
        &#125;
        cur.t = t;
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append("LinkedList ");
        Node cur = dummyHead.next;
        while(cur != null)&#123;
            stringBuilder.append(cur.t +" -> ");
            cur = cur.next;
        &#125;
        stringBuilder.append("NULL");
        return stringBuilder.toString();
    &#125;

    public static void main(String[] args) &#123;
        LinkedList&lt;Integer> list = new LinkedList&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            list.addFirst(i);
        &#125;
        list.add(3,99);
        System.out.println(list);
        list.remove(3);
        System.out.println(list);
        System.out.println(list.contains(5));

    &#125;
&#125;

栈package datastructure.stack;

import datastructure.Array.Array;

/**
 * 使用动态数组实现栈
 * @param &lt;T>
 */
public class ArrayStack&lt;T> implements Stack&lt;T>&#123;
    private Array&lt;T> array;
    public ArrayStack()&#123;
        array = new Array&lt;>();
    &#125;
    public ArrayStack(int capacity)&#123;
        array = new Array&lt;>(capacity);
    &#125;
    @Override
    public int getSize() &#123;
        return array.getSize();
    &#125;
    public int getCapacity()&#123;
        return array.getCapacity();
    &#125;

    @Override
    public boolean isEmpty() &#123;
        return array.isEmpty();
    &#125;

    @Override
    public T pop() &#123;
        return array.removeLast();
    &#125;

    @Override
    public void push(T t) &#123;
        array.addLast(t);
    &#125;

    @Override
    public T peek() &#123;
        return array.getLast();
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append("ArrayStack [ ");
        for (int i = 0; i &lt; getSize(); i++) &#123;
            stringBuilder.append(array.get(i));
            if(i != getSize() -1)
                stringBuilder.append(" , ");
        &#125;
        stringBuilder.append(" ] top");
        return stringBuilder.toString();
    &#125;

    public static void main(String[] args) &#123;
        ArrayStack&lt;Integer> arrayStack = new ArrayStack&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            arrayStack.push(i);
            if(i % 3 == 2)&#123;
                arrayStack.pop();
            &#125;
            System.out.println(arrayStack);
        &#125;


    &#125;
&#125;

链表实现栈package datastructure.stack;

import datastructure.linkedlist.LinkedList;

public class LinkedListStack&lt;T> implements Stack&lt;T>&#123;
    private LinkedList&lt;T> list;
    public LinkedListStack()&#123;
        list = new LinkedList&lt;>();
    &#125;
    @Override
    public int getSize() &#123;
        return list.getSize();
    &#125;

    @Override
    public boolean isEmpty() &#123;
        return list.isEmpty();
    &#125;

    @Override
    public T pop() &#123;
        return list.removeFitrst();
    &#125;

    @Override
    public void push(T t) &#123;
        list.addFirst(t);
    &#125;

    @Override
    public T peek() &#123;
        return list.getFirst();
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append("LinkedListStack top ");
        stringBuilder.append(list.toString().substring(11));
        return stringBuilder.toString();
    &#125;

    public static void main(String[] args) &#123;
        LinkedListStack&lt;Integer> stack = new LinkedListStack&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            stack.push(i);
            System.out.println(stack);
            if(i % 3 == 2)&#123;
                stack.pop();
                System.out.println(stack);
            &#125;
        &#125;
    &#125;
