循环队列package datastructure.queue;

/**
 *循环队列实现，目的是为了使出队操作的均摊复杂度为O(1)
 * @param &lt;T>
 */
public class LoopQueue&lt;T> implements Queue&lt;T> &#123;
    private T[] data;//存放数据
    private int front;//标识队列的头部
    private int tail;//标识队列的尾部的下一个位置
    private int size;//标识队列中的元素个数
    /*
    *说明：
    * 1.队空条件：front = tail
    * 2.队满条件:尾部元素的下一个元素是队首元素，使得我们必须浪费一个空间标记队满
    * 3.队满时添加元素要扩容
     */
    public LoopQueue(int capacity)&#123;
        data = (T[]) new Object[capacity + 1];//我们浪费了一个空间，用户是不知道的。
        front = 0;
        tail = 0;
        size = 0;
    &#125;
    public LoopQueue()&#123;
        this(10);
    &#125;
    @Override
    public int getSize() &#123;
        return size;
    &#125;
    public int getCapacity()&#123;
        return data.length -1;
    &#125;
    @Override
    public boolean isEmpty() &#123;
        return size == 0;
    &#125;
    @Override
    public void enqueue(T t) &#123;
        if((tail+1)% data.length == front)//if(size == getCapacity())//有一个空间浪费
            resize(getCapacity() &lt;&lt; 1);//扩容
        data[tail] = t;
        tail = (tail + 1) % data.length;
        size++;
    &#125;
    private void resize(int newCapacity)&#123;
        T[] newData = (T[]) new Object[newCapacity + 1];
        for (int i = 0; i &lt; size; i++) &#123;
            newData[i] = data[front];
            front = (front+1) % data.length;
        &#125;
        data = newData;
        front = 0;
        tail = size;
    &#125;
    @Override
    public T dequeue() &#123;
        T t = data[front];
        data[front] = null;
        front = (front +1) % data.length;
        size--;
        if(size == getCapacity() >> 2 &amp;&amp; getCapacity() >> 1 != 0 )
            resize(getCapacity() >> 1);
        return t;
    &#125;

    @Override
    public T getFront() &#123;
        return data[front];
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append(String.format("LoopQueue [size:%d , capacity:%d]\n",size,getCapacity()));
        stringBuilder.append("LoopQueue front [ ");
        for (int i = front; i != tail ; i = (i + 1) % data.length) &#123;
            stringBuilder.append(data[i]);
            if ((i + 1) % data.length != tail)
                stringBuilder.append(" , ");
        &#125;
        stringBuilder.append(" ] tail");
        return stringBuilder.toString();
    &#125;
    public static void main(String[] args) &#123;
        LoopQueue&lt;Integer> loopQueue = new LoopQueue&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            loopQueue.enqueue(i);
            if(i % 3 == 2)
                loopQueue.dequeue();
            System.out.println(loopQueue);
        &#125;
//        System.out.println(loopQueue);
//        loopQueue.enqueue(100);
//        System.out.println(loopQueue);
//        loopQueue.dequeue();
//        System.out.println(loopQueue);
    &#125;
&#125;

链表实现队列package datastructure.queue;

import datastructure.stack.LinkedListStack;

public class LinkedListQueue&lt;T> implements Queue&lt;T> &#123;
    private class Node&#123;
        public T t;
        public Node next;
        public Node(T t,Node next)&#123;
            this.t = t;
            this.next = next;
        &#125;
        public Node(T t)&#123;
            this(t,null);
        &#125;
        public Node()&#123;
            this(null,null);
        &#125;

        @Override
        public String toString() &#123;
            return t.toString();
        &#125;
    &#125;
    //设置含有尾指针的链表实现队列
    //注意点：空元素队列的插入head的处理，和最后一个元素删除tail的处理
    private Node head;
    private Node tail;
    private int size;
    public LinkedListQueue()&#123;
        head = null;
        tail = null;
        size = 0;
    &#125;
    @Override
    public int getSize() &#123;
        return size;
    &#125;

    @Override
    public boolean isEmpty() &#123;
        return size == 0;
    &#125;

    @Override
    public void enqueue(T t) &#123;
        //判断是否是第一个元素入队
        if(tail == null)&#123;
            tail = new Node(t);
            head = tail;
        &#125;else &#123;
            tail.next = new Node(t);
            tail = tail.next;
        &#125;
        size++;
    &#125;

    @Override
    public T dequeue() &#123;
        //注意出队最后一个元素tail的处理
        if(head == null)
            throw new IllegalArgumentException("队列为空无法删除。");
        Node retNode = head;
        head = head.next;
        retNode.next = null;
        if(head == null)//删除最后一个元素要注意
            tail = null;
        return retNode.t;
    &#125;

    @Override
    public T getFront() &#123;
        return head.t;
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder();
        stringBuilder.append("LinkedListQueue front ");
        Node cur = head;
        while (cur != null)&#123;
            stringBuilder.append(cur.t +" -> ");
            cur = cur.next;
        &#125;
        stringBuilder.append("NULL tail");
        return stringBuilder.toString();
    &#125;

    public static void main(String[] args) &#123;
        LinkedListQueue&lt;Integer> Queue = new LinkedListQueue&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            Queue.enqueue(i);
            System.out.println(Queue);
            if(i % 3 == 2)&#123;
                Queue.dequeue();
                System.out.println(Queue);
            &#125;
        &#125;
    &#125;
&#125;

