/**
 * Created with IntelliJ IDEA.
 *
 * @Author: 陈进松
 * @Date: 2021/10/13/4:39
 * @Description:
 */
@Configuration
public class QuartzConfig &#123;
    //配置JobDetail和Trigger
    @Bean
    public JobDetail jobDetail()&#123;
        JobDetail jobDetail = JobBuilder.newJob(UserJob.class)
                //为JobDetail去一个名字，选择一个分组
                .withIdentity("userJob", "userJob")
                //向JobDataMap中存一些数据
                .usingJobData("username", "张三")
                .usingJobData("age", 20)
                //选择是否持久化
                .storeDurably(true)
                .build();
        return jobDetail;
    &#125;
    //配置Trigger cronTrigger或者simpleTrigger
//    @Bean
    public Trigger cronTrigger()&#123;
        CronTrigger cronTrigger = TriggerBuilder.newTrigger()
                //为Trigger取名字和选择分组
                .withIdentity("userJobTrigger", "userJobTrigger")
                //指定为哪一个Job的trigger
                .forJob(jobDetail())
                //创建调度器，并指定任务的执行规则
                .withSchedule(CronScheduleBuilder.cronSchedule("0/5 * * * * ?"))
                .build();
        return cronTrigger ;
    &#125;
    @Bean
    public Trigger trigger()&#123;
        SimpleTrigger simpleTrigger = TriggerBuilder.newTrigger()
                //为Trigger取名字和选择分组
                .withIdentity("userJobTrigger", "userJobTrigger")
                //指定为哪一个Job的trigger
                .forJob(jobDetail())
                //创建调度器，并指定任务的执行规则
                .withSchedule(SimpleScheduleBuilder.repeatSecondlyForever(5))
                .build();
        return simpleTrigger ;
    &#125;
