BST（二分搜索树）
/**
 * 二分搜索树
 */
public class BST&lt;T extends Comparable&lt;T>> &#123;
    private class Node &#123;
        public T t;
        public Node left, right;

        public Node(T t) &#123;
            this.t = t;
        &#125;
    &#125;

    private Node root;
    private int size;

    public int size() &#123;
        return size;
    &#125;

    public boolean isEmpty() &#123;
        return size == 0;
    &#125;

    //向二分搜索树中添加元素
    public void add(T t) &#123;
        root = add(root, t);
    &#125;

    private Node add(Node node, T t) &#123;
        if (node == null)//当前节点为空插入新节点
            return new Node(t);
        if (t.compareTo(node.t) &lt; 0)//插入的值比当前的值小，往当前左子树中插入，左指针指向插入完成后的左子树
            node.left = add(node.left, t);
        else if (t.compareTo(node.t) > 0)//插入的值比当前节点的值大，往当前节点的右子树插入
            node.right = add(node.right, t);
        //相等情况不做处理
        return node;//返回插入完成后的根节点
    &#125;

    //查询二叉搜索树中是否包含某个元素
    public boolean contains(T t) &#123;
        return contains(root, t);
    &#125;

    private boolean contains(Node node, T t) &#123;
        if (node == null)
            return false;
        if (t.compareTo(node.t) &lt; 0)//查询的值比当前的值小，返回其左子树中查询的结果
            return contains(node.left, t);
        else if (t.compareTo(node.t) > 0)//查询的值比当前的值大，返回其右子树中查询的结果
            return contains(node.right, t);
        else //找到查询的值
            return true;
    &#125;

    //二叉搜索树前序遍历
    public void preOrder() &#123;
        preOrder(root);
    &#125;

    private void preOrder(Node node) &#123;
        if (node == null)
            return;
        //前序遍历：根左右
        System.out.print(node.t + "->");
        preOrder(node.left);
        preOrder(node.right);
    &#125;

    //前序遍历非递归,深度优先遍历使用栈结构
    public void preOrderNR() &#123;
        Stack&lt;Node> stack = new Stack&lt;>();
        stack.push(root);
        while (!stack.isEmpty()) &#123;//栈不为空，先后将右子树和左子树入栈
            Node cur = stack.pop();
            System.out.println(cur.t);
            if (cur.right != null)
                stack.push(cur.right);
            if (cur.left != null)
                stack.push(cur.left);

        &#125;

    &#125;

    //中序遍历：有序遍历，左根右
    public void inOrder() &#123;
        inOrder(root);
    &#125;

    private void inOrder(Node node) &#123;
        if (node == null)
            return;
        inOrder(node.left);
        System.out.print(node.t + "->");
        inOrder(node.right);
    &#125;

    //后序遍历：左右根
    public void postOrder() &#123;
        postOrder(root);
    &#125;

    private void postOrder(Node node) &#123;
        if (node == null)
            return;
        postOrder(node.left);
        postOrder(node.right);
        System.out.print(node.t + "->");
    &#125;

    //层序遍历，广度优先遍历使用队列
    public void levelOrder() &#123;
        Queue&lt;Node> queue = new LinkedList&lt;>();
        queue.add(root);
        while (!queue.isEmpty()) &#123;//队列不为空，左右子树先后入队
            Node cur = queue.remove();
            System.out.println(cur.t);
            if (cur.left != null)
                queue.add(cur.left);
            if (cur.right != null)
                queue.add(cur.right);
        &#125;
    &#125;

    //删除相关操作
    public T min() &#123;
        return min(root).t;
    &#125;

    private Node min(Node node) &#123;
        if (node.left == null)
            return node;
        return min(node.left);
    &#125;

    public T max() &#123;
        return max(root).t;
    &#125;

    private Node max(Node node) &#123;
        if (node.right == null)
            return node;
        return max(node.right);
    &#125;

    //删除最大值或最小值
    public T removeMin() &#123;
        T ret = min();
        root = removeMin(root);
        return ret;
    &#125;

    private Node removeMin(Node node) &#123;
        //两种情况叶子结点或只有右子树
        if (node.left == null) &#123;//找到最小节点
            Node rightNode = node.right;//记录右节点
            node.right = null;//删除节点
            size--;
            return rightNode;//返回右节点
        &#125;
        //没有找到最小节点,继续向左删除
        node.left = removeMin(node.left);
        return node;//返回删除最小节点的根节点
    &#125;

    public T removeMax() &#123;
        T ret = max();
        root = removeMax(root);
        return ret;
    &#125;

    private Node removeMax(Node node) &#123;
        if (node.right == null) &#123;
            Node leftNode = node.left;
            node.left = null;
            size--;
            return leftNode;
        &#125;
        node.right = removeMax(node.right);
        return node;
    &#125;

    //删除BST中的任意节点
    public void remove(T t) &#123;
        root = remove(root, t);
    &#125;

    //三种情况，当前删除节点只有右子树，只有左子树，左右子树都有
    private Node remove(Node node, T t) &#123;
        if (node == null)//没有找到要删除的节点
            return null;
        if (t.compareTo(node.t) &lt; 0) &#123;
            //比当前节点小往左边查找要删除的元素
            node.left = remove(node.left, t);
            return node;//返回删除了元素的根节点
        &#125; else if (t.compareTo(node.t) > 0) &#123;
            //比当前节点大，往右边查找
            node.right = remove(node.right, t);
            return node;
        &#125; else &#123;//找到要删除元素，进行删除，三种情况
            //第一种只有左子树
            if (node.right == null) &#123;
                Node leftNode = node.left;
                node.left = null;
                size--;
                return leftNode;
            &#125;
            //只有右子树
            else if (node.left == null) &#123;
                Node rightNode = node.right;
                node.right = null;
                size--;
                return rightNode;
            &#125;
            //左右子树均有,有当前节点的有子树的最小节点替换当前节点的位置，删除最小节点
            else &#123;
                Node successor = min(node.right);//获取右子树最小节点
                //不用维护size，removeMin已经维护了
                successor.right = removeMin(node.right);
                successor.left = node.left;
                node.left = node.right = null;
                return successor;//返回删除元素的根节点
            &#125;
        &#125;
    &#125;

    public static void main(String[] args) &#123;
        BST&lt;Integer> bst = new BST&lt;>();
        for (int i = 0; i &lt; 10; i++) &#123;
            bst.add(new Random().nextInt(100));
        &#125;
        bst.inOrder();
        System.out.println();
        bst.remove(bst.max());
        bst.inOrder();
    &#125;
&#125;

AVLTree (平衡二叉树)public class AVLTree&lt;T extends Comparable&lt;T>> &#123;
    private class Node &#123;
        public T val;
        public int height;
        public Node left;
        public Node right;

        public Node(T val, Node left, Node right) &#123;
            this.val = val;
            this.left = left;
            this.right = right;
        &#125;

        public Node(T data) &#123;
            this(data, null, null);
        &#125;

        public Node() &#123;

        &#125;
    &#125;

    private Node root;
    private int size;

    public int getSize() &#123;
        return size;
    &#125;

    //添加元素
    public void add(T t) &#123;
        root = add(root, t);
    &#125;

    private Node add(Node node, T t) &#123;
        if (node == null) &#123;
            node = new Node(t);
            node.height = 1;
            size++;
        &#125;
        if (node.val.compareTo(t) > 0) &#123;
            node.left = add(node.left, t);
        &#125; else if (node.val.compareTo(t) &lt; 0) &#123;
            node.right = add(node.right, t);
        &#125; else &#123;
            //重复不处理
        &#125;
        //平衡二叉树维护
        //树的高度维护
        node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
        int balancefactor = getBanlanceFactor(node);

        //LL 模式，在节点的左侧的左侧添加元素导致当前节点不平衡
        if (balancefactor > 1 &amp;&amp; getBanlanceFactor(node.left) > 0)
            return rightRatato(node);
        //RR
        if (balancefactor &lt; -1 &amp;&amp; getBanlanceFactor(node.right) &lt; 0)
            return leftRatato(node);
        //LR
        if (balancefactor > 1 &amp;&amp; getBanlanceFactor(node.left) &lt; 0) &#123;
            node.left = leftRatato(node.left);
            return rightRatato(node);
        &#125;
        //RL
        if (balancefactor &lt; -1 &amp;&amp; getBanlanceFactor(node.right) > 0) &#123;
            node.right = rightRatato(node.right);
            return leftRatato(node);
        &#125;
//        if (balancefactor != 0)
//            System.out.println("balancefactor:"+balancefactor);
        return node;
    &#125;

    //右旋转并返回右旋转后的节点
    private Node rightRatato(Node node) &#123;
        Node left = node.left;
        Node leftright = left.right;
        //旋转操作
        left.right = node;
        node.left = leftright;
        //维护高度,顺序不能反
        node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
        left.height = 1 + Math.max(getHeight(left.left), getHeight(left.right));
        return left;
    &#125;

    private Node leftRatato(Node node) &#123;
        Node right = node.right;
        Node rightleft = right.left;
        //旋转操作
        right.left = node;
        node.right = rightleft;
        //高度更新
        node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
        right.height = 1 + Math.max(getHeight(right.left), getHeight(right.right));
        return right;
    &#125;

    //获取当前节点的高度
    private int getHeight(Node node) &#123;
        //空节点为0，叶子节点高度为1
        if (node == null)
            return 0;
        return node.height;
    &#125;

    //获取当前节点的平衡因子
    private int getBanlanceFactor(Node node) &#123;
        if (node == null)
            return 0;
        //左子树高度减右子树高度
        return getHeight(node.left) - getHeight(node.right);
    &#125;

    public boolean isBST() &#123;
        List&lt;T> list = inOrder();
        for (int i = 0; i &lt; list.size() - 1; i++) &#123;
            if (list.get(i).compareTo(list.get(i + 1)) > 0)
                return false;
        &#125;
        return true;
    &#125;

    public boolean isBalanced() &#123;
        return isBalanced(root);
    &#125;

    private boolean isBalanced(Node node) &#123;
        if (node == null)
            return true;
        if (Math.abs(getBanlanceFactor(node)) > 1)
            return false;
        //左右子树都平衡才行。
        return isBalanced(node.left) &amp;&amp; isBalanced(node.right);
    &#125;

    public List&lt;T> preOrder() &#123;
        List&lt;T> list = new ArrayList&lt;>();
        preOrder(root, list);
        return list;
    &#125;

    private void preOrder(Node node, List&lt;T> list) &#123;
        if (node == null)
            return;
        list.add(node.val);
        preOrder(node.left, list);
        preOrder(node.right, list);
    &#125;

    public List&lt;T> inOrder() &#123;
        List&lt;T> list = new ArrayList&lt;>();
        inOrder(root, list);
        return list;
    &#125;

    private void inOrder(Node node, List&lt;T> list) &#123;
        if (node == null)
            return;
        inOrder(node.left, list);
        list.add(node.val);
        inOrder(node.right, list);
    &#125;

    public List&lt;T> postOrder() &#123;
        List&lt;T> list = new ArrayList&lt;>();
        postOrder(root, list);
        return list;
    &#125;

    private void postOrder(Node node, List&lt;T> list) &#123;
        if (node == null)
            return;
        postOrder(node.left, list);
        postOrder(node.right, list);
        list.add(node.val);
    &#125;

    public T min() &#123;
        return min(root).val;
    &#125;

    private Node min(Node node) &#123;
        if (node == null)
            return null;
        if (node.left == null)
            return node;
        return min(node.left);
    &#125;

    public T max() &#123;
        return max(root);
    &#125;

    private T max(Node node) &#123;
        if (node == null)
            return null;
        if (node.right == null)
            return node.val;
        return max(node.right);
    &#125;

    public T removeMin() &#123;
        T min = min();
        root = removeMin(root);
        return min;
    &#125;

    private Node removeMin(Node node) &#123;
        if (node == null)
            return null;
        if (node.left == null) &#123;
            Node right = node.right;
            node.right = null;
            size--;
            return right;
        &#125;
        node.left = removeMin(node.left);
        return node;
    &#125;

    //删除指定值
    public void remove(T t) &#123;
        root = remove(root, t);
    &#125;

    private Node remove(Node node, T t) &#123;
        if (node == null)
            return null;
        Node retNode;//用于记录返回节点，对平衡进行处理
        if (node.val.compareTo(t) > 0) &#123;
            node.left = remove(node.left, t);
            retNode = node;
        &#125; else if (node.val.compareTo(t) &lt; 0) &#123;
            node.right = remove(node.right, t);
            retNode = node;
        &#125; else &#123;
            if (node.left == null) &#123;
                Node right = node.right;
                node.right = null;
                size--;
                retNode = node;
            &#125; else if (node.right == null) &#123;
                Node left = node.left;
                node.left = null;
                size--;
                retNode = node;
            &#125; else &#123;
                Node successor = min(node.right);
                successor.right = remove(node.left, successor.val);
                successor.left = node.left;
                node.left = node.right = null;
                retNode = successor;
            &#125;
        &#125;
        retNode.height = 1 + Math.max(getHeight(retNode.left), getHeight(retNode.right));
        int balancefactor = getBanlanceFactor(retNode);

        //LL 模式，在节点的左侧的左侧添加元素导致当前节点不平衡
        if (balancefactor > 1 &amp;&amp; getBanlanceFactor(retNode.left) > 0)
            return rightRatato(retNode);
        //RR
        if (balancefactor &lt; -1 &amp;&amp; getBanlanceFactor(retNode.right) &lt; 0)
            return leftRatato(retNode);
        //LR
        if (balancefactor > 1 &amp;&amp; getBanlanceFactor(retNode.left) &lt; 0) &#123;
            retNode.left = leftRatato(retNode.left);
            return rightRatato(retNode);
        &#125;
        //RL
        if (balancefactor &lt; -1 &amp;&amp; getBanlanceFactor(retNode.right) > 0) &#123;
            retNode.right = rightRatato(retNode.right);
            return leftRatato(retNode);
        &#125;
        return retNode;
    &#125;

