SegmentTree (线段树)//线段树，用于处理区间问题，每一个节点都是区间操作的结果
//使用数组实现
public class SegmentTree&lt;T> &#123;
    private T[] tree;//树结构，用于存储处理后的数据
    private T[] data;//用于存储区间数据
    private Merge&lt;T> merge;

    public SegmentTree(T[] arr, Merge&lt;T> merge) &#123;
        //初始化操作
        data = (T[]) new Object[arr.length];
        tree = (T[]) new Object[4 * arr.length];//线段树中的节点数是区间的4倍
        for (int i = 0; i &lt; arr.length; i++) &#123;
            data[i] = arr[i];//保存区间数据的副本
        &#125;
        this.merge = merge;
        //创建线段树
        createSegmentTree(0, 0, data.length - 1);
    &#125;

    private void createSegmentTree(int treeIndex, int l, int r) &#123;
        if (l == r) &#123;//左右端点相等，到达叶子节点
            tree[treeIndex] = data[l];
            return;
        &#125;
        int leftChild = leftChild(treeIndex);
        int rightChild = rightChild(treeIndex);
        int mid = l + (r - l) / 2;//区间分段
        //从下到上创建线段树
        //创建左子树
        createSegmentTree(leftChild, l, mid);
        //创建右子树
        createSegmentTree(rightChild, mid + 1, r);
        //左右孩子的结果汇总到根节点
        tree[treeIndex] = merge.merge(tree[leftChild], tree[rightChild]);

    &#125;

    //获取左孩子索引
    private int leftChild(int treeIndex) &#123;
        return 2 * treeIndex + 1;
    &#125;

    //获取右孩子索引
    private int rightChild(int treeIndex) &#123;
        return 2 * treeIndex + 2;
    &#125;

    public int getSize() &#123;
        return data.length;
    &#125;

    //查询区间值
    public T query(int queryl, int queryr) &#123;
        //边界检查
        if (queryl &lt; 0 || queryl >= data.length || queryr &lt; 0 || queryr >= data.length || queryl > queryr)
            throw new ArrayIndexOutOfBoundsException("下标越界！");
        return query(0, 0, data.length - 1, queryl, queryr);
    &#125;

    //递归查询区间值
    private T query(int treeIndex, int l, int r, int queryl, int queryr) &#123;
        if (l == queryl &amp;&amp; r == queryr)
            return tree[treeIndex];
        int leftChild = leftChild(treeIndex);
        int rightChild = rightChild(treeIndex);
        int mid = l + (r - l) / 2;//避免整型溢出
        //三种情况，在左子树，在右子树，左右子树都有
        //左子树
        if (queryr &lt;= mid) &#123;
            return query(leftChild, l, mid, queryl, queryr);
        &#125; else if (queryl >= mid + 1) &#123;
            return query(rightChild, mid + 1, r, queryl, queryr);
        &#125; else &#123;
            T resultl = query(leftChild, l, mid, queryl, mid);
            T resultr = query(rightChild, mid + 1, r, mid + 1, queryr);
            return merge.merge(resultl, resultl);
        &#125;
    &#125;

    public void set(int index, T t) &#123;
        if (index &lt; 0 || index >= data.length)
            throw new IllegalArgumentException("下标越界！");
        data[index] = t;
        set(0, 0, data.length - 1, index, t);
    &#125;

    //index就是边界
    private void set(int treeIndex, int l, int r, int index, T t) &#123;
        if (l == r) &#123;
            tree[treeIndex] = t;
            return;
        &#125;
        int leftTreeIndex = leftChild(treeIndex);
        int rightTreeIndex = rightChild(treeIndex);
        int mid = l + (r - l) / 2;
        if (index &lt;= mid) &#123;
            set(leftTreeIndex, l, mid, index, t);
        &#125; else &#123;
            set(rightTreeIndex, mid + 1, r, index, t);
        &#125;
        //更新节点的父节点
        tree[treeIndex] = merge.merge(tree[leftTreeIndex], tree[rightTreeIndex]);
    &#125;

    @Override
    public String toString() &#123;
        StringBuilder stringBuilder = new StringBuilder("SegmentTree: ");
        for (int i = 0; i &lt; tree.length; i++) &#123;
            if (tree[i] != null) &#123;
                stringBuilder.append(tree[i] + "->");
            &#125;
        &#125;
        return stringBuilder.toString();
    &#125;
&#125;


Trie（字典树）//用于字符串中
public class Trie &#123;
    private class Node &#123;
        public boolean isWord;//判断是否是一个单词的结尾
        public TreeMap&lt;Character, Node> next;//每一个节点映射到若干个节点

        public Node(boolean isWord) &#123;
            this.isWord = isWord;
            next = new TreeMap&lt;>();
        &#125;

        public Node() &#123;
            this(false);
        &#125;
    &#125;

    private Node root;//根节点
    private int size;//记录单词的个数

    public Trie() &#123;
        root = new Node();
        size = 0;
    &#125;

    public int getSize() &#123;
        return size;
    &#125;

    //添加一个单词
    public void add(String word) &#123;
        Node cur = root;
        for (int i = 0; i &lt; word.length(); i++) &#123;
            char c = word.charAt(i);
            if (cur.next.get(c) == null)//如果当前节点的下一个节点不存在，则创建一个新节点
                cur.next.put(c, new Node());
            cur = cur.next.get(c);//走向下一个节点
        &#125;
        if (!cur.isWord) &#123;//不是一个单词设置成一个单词，避免找到的是前缀
            cur.isWord = true;
            size++;
        &#125;
    &#125;

    //判断一个单词是否存在
    public boolean contains(String word) &#123;
        Node cur = root;
        for (int i = 0; i &lt; word.length(); i++) &#123;
            char c = word.charAt(i);//相当于存储在路径上的
            if (cur.next.get(c) == null)//字符串没有走完，就找不到节点表示没有这个节点
                return false;
            cur = cur.next.get(c);
        &#125;
        return cur.isWord;//不能直接返回true，有可能是一个单词的前缀。
    &#125;

