    //自底向上的归并排序
    private void mergerSortBU(int[] arr) &#123;
        for (int sz = 1; sz &lt;= arr.length; sz += sz) &#123;
            for (int i = 0; i + sz &lt; arr.length; i += sz + sz) &#123;
                merge(arr, i, i + sz - 1, Math.min(i + sz + sz - 1, arr.length - 1));
            &#125;
        &#125;
    &#125;

    private void mergerSort(int[] arr, int l, int r) &#123;
        if (l >= r)
            return;
        int mid = l + (r - l) / 2;
        //左边排序
        mergerSort(arr, l, mid);
        //右边排序
        mergerSort(arr, mid + 1, r);
        //归并,当两个数组完全有序不用归并
        if (arr[mid] > arr[mid + 1])
            merge(arr, l, mid, r);
    &#125;

    private void merge(int[] arr, int l, int mid, int r) &#123;
        //创建临时数组
        int[] temp = new int[r - l + 1];
        for (int i = l; i &lt;= r; i++) &#123;
            temp[i - l] = arr[i];
        &#125;
        int i = l;
        int j = mid + 1;
        for (int k = l; k &lt;= r; k++) &#123;
            if (i > mid) &#123;
                arr[k] = temp[j - l];
                j++;
            &#125; else if (j > r) &#123;
                arr[k] = temp[i - l];
                i++;
            &#125; else if (temp[i - l] > temp[j - l]) &#123;
                arr[k] = temp[j - l];
                j++;
            &#125; else &#123;
                arr[k] = temp[i - l];
                i++;
            &#125;
        &#125;
    &#125;
