快速排序public class QuickSort implements Sort &#123;
    @Override
    public void sort(int[] arr) &#123;
//        quickSort(arr,0,arr.length-1);
        quickSort3Ways(arr, 0, arr.length - 1);
    &#125;

    private void quickSort(int[] arr, int l, int r) &#123;
        if (l >= r)
            return;
        int p = partition2(arr, l, r);
        quickSort(arr, l, p);
        quickSort(arr, p + 1, r);
    &#125;

    //[l+1->j] 小于目标值，[j+1->i) 大于目标值 i是当前遍历元素
    private int partition(int[] arr, int l, int r) &#123;
        Sort.swap(arr, l, (int) (Math.random() * (r - l + 1) + l));
        int temp = arr[l];
        int j = l;
        for (int i = l + 1; i &lt;= r; i++) &#123;
            if (arr[i] &lt; temp) &#123;
                Sort.swap(arr, j + 1, i);
                j++;
            &#125;
        &#125;
        Sort.swap(arr, l, j);
        return j;
    &#125;

    //双路快排 l+1->i-1 小于目标值  j+1 -> r 大于目标值
    private int partition2(int[] arr, int l, int r) &#123;
        Sort.swap(arr, l, (int) (Math.random() * (r - l + 1) + l));
        int temp = arr[l];
        int i = l + 1;
        int j = r;
        while (true) &#123;
            while (i &lt;= r &amp;&amp; arr[i] &lt; temp)//arr[i] &lt; temp不能等于，否则排序数和极度不平衡
                i++;
            while ((j >= l + 1 &amp;&amp; arr[j] > temp))
                j--;
            if (i > j)
                break;
            Sort.swap(arr, i, j);
            i++;
            j--;
        &#125;
        Sort.swap(arr, l, j);
        return j;
    &#125;

    private void quickSort3Ways(int[] arr, int l, int r) &#123;
        if (l >= r)
            return;
        int[] p = partition3Ways(arr, l, r);
        quickSort3Ways(arr, l, p[0]);
        quickSort3Ways(arr, p[1], r);

    &#125;

    //三路快排 l+1->lt 小于目标值 lt+1 -> i-1 等于目标值 gt->r 大于目标值 主要用于重复值较多的排序中
    private int[] partition3Ways(int[] arr, int l, int r) &#123;
        int lt = l;
        int gt = r + 1;
        int i = l + 1;
        Sort.swap(arr, l, (int) (Math.random() * (r - l + 1) + l));
        int temp = arr[l];
        while (i &lt; gt) &#123;//处理元素达到大于区域
            if (arr[i] &lt; temp) &#123;
                Sort.swap(arr, lt + 1, i);
                i++;
                lt++;
            &#125; else if (arr[i] > temp) &#123;
                Sort.swap(arr, gt - 1, i);
                gt--;
            &#125; else &#123;//相等情况
                i++;
            &#125;
        &#125;
        Sort.swap(arr, l, lt);//交换后it位置等于目标值
        return new int[]&#123;lt - 1, gt&#125;;
    &#125;
