public class KMP &#123;
    public int hasSubString(String str1, String str2) &#123;
        int[] next = getNext(str2);
        int i = 0;
        int j = 0;
        while (i &lt; str1.length() &amp;&amp; j &lt; str2.length()) &#123;
            if (j == -1 || str1.charAt(i) == str2.charAt(j)) &#123;
                i++;
                j++;
            &#125; else
                j = next[j];
        &#125;
        if (j == str2.length())
            return i - j;
        return -1;
    &#125;

    private int[] getNext(String str2) &#123;
        int[] next = new int[str2.length()];
        next[0] = -1;
        int k = -1;
        int j = 0;
        while (j &lt; next.length - 1) &#123;
            if (k == -1 || str2.charAt(k) == str2.charAt(j)) &#123;
                ++k;
                ++j;
                if (str2.charAt(k) != str2.charAt(j))
                    next[j] = k;
                else
                    next[j] = next[k];
            &#125; else
                k = next[k];
        &#125;
        return next;
    &#125;

