/**
 * 二叉堆的实现，动态数组实现
 *
 * @param &lt;T>
 */
public class MaxHeap&lt;T extends Comparable&lt;T>> &#123;
    private Array&lt;T> data;

    public MaxHeap(int capacity) &#123;
        data = new Array&lt;>(capacity);
    &#125;

    public MaxHeap() &#123;
        data = new Array&lt;>();
    &#125;

    //heapfiy：将数组变为堆
    public MaxHeap(T[] arr) &#123;
        data = new Array&lt;>(arr);
        //找到堆的最后一个非叶子节点，从这个节点开始往前不断执行下沉操作
        for (int i = parent(getSize() - 1); i >= 0; i--) &#123;
            siftDown(i);
        &#125;
    &#125;

    public int getSize() &#123;
        return data.getSize();
    &#125;

    public boolean isEmpty() &#123;
        return data.isEmpty();
    &#125;

    //向堆中添加元素
    public void add(T t) &#123;
        //将元素添加到数组的最后
        data.addLast(t);
        //元素不断上浮使整个数组满足对的定义
        siftUp(getSize() - 1);
    &#125;

    //获取指定索引节点的父节点
    private int parent(int k) &#123;
        if (k &lt;= 0)
            throw new IllegalArgumentException("not root");
        return (k - 1) / 2;
    &#125;

    //获取指定节点的左孩子节点的索引
    private int leftChild(int k) &#123;
        return k * 2 + 1;
    &#125;

    //获取指定节点的的右孩子的索引
    private int rightChild(int k) &#123;
        return k * 2 + 2;
    &#125;

    private void siftUp(int k) &#123;
        //当前节点不断与其父节点比较，比父节点大就进行交换
        //k > 0 表示没有越界和非root节点
        while (k > 0 &amp;&amp; data.get(parent(k)).compareTo(data.get(k)) &lt; 0) &#123;
            data.swap(k, parent(k));
            k = parent(k);
        &#125;
    &#125;

    //获取heap中的最大元素
    public T findMax() &#123;
        if (getSize() == 0)
            throw new IllegalArgumentException("堆为空");
        return data.get(0);
    &#125;

    //删除对顶元素
    public T removeMax() &#123;
        T ret = findMax();
        //对顶元素与最后一个元素交换
        data.swap(0, getSize() - 1);
        //删除最后一个元素
        data.removeLast();
        //堆顶元素下沉维持堆对的定义
        siftDown(0);
        return ret;
    &#125;

    private void siftDown(int k) &#123;
        //完全二叉树的非叶子节点至少有一个左孩子
        while (leftChild(k) &lt; getSize()) &#123;
            //将根节点与左右子树的最大值进行交换
            int j = leftChild(k);//记录左孩子的索引
            //有右孩子且右孩子的值大于左孩子，最大索引指向右孩子
            if (j + 1 &lt; getSize() &amp;&amp; data.get(j + 1).compareTo(data.get(j)) > 0)
                j++;
            //比较当前节点与其左右孩子中的最大值，当前节点大跳出循环
            if (data.get(k).compareTo(data.get(j)) > 0)
                break;
            data.swap(k, j);
            k = j;
        &#125;
    &#125;

    //替换root节点
    public T repleace(T t) &#123;
        T ret = findMax();
        siftDown(0);
        return ret;
    &#125;

    public static void main(String[] args) &#123;
        Integer[] arr = new Integer[10];
        for (int i = 0; i &lt; 10; i++) &#123;
            arr[i] = i;
        &#125;
        MaxHeap&lt;Integer> heap = new MaxHeap&lt;>(arr);
        for (int i = 0; i &lt; 10; i++) &#123;
            System.out.println(heap.removeMax());
        &#125;

    &#125;
&#125;

public class HashTable&lt;K, V> &#123;
    //扩容的平均hash冲突上下限
    public static final int UpperTol = 10;
    public static final int LowerTol = 2;
    public static final int initCapacity = 7;
    private TreeMap&lt;K, V>[] hashtable;
    private int M;
    private int size;

    public HashTable(int M) &#123;
        this.M = M;
        size = 0;
        hashtable = new TreeMap[M];
        for (int i = 0; i &lt; M; i++) &#123;
            hashtable[i] = new TreeMap&lt;>();
        &#125;
    &#125;

    public HashTable() &#123;
        this(initCapacity);
    &#125;

    private int hash(K key) &#123;
        return (key.hashCode() &amp; 0x7fffffff) % M;
    &#125;

    public int getSize() &#123;
        return size;
    &#125;

    public void add(K key, V val) &#123;
        TreeMap&lt;K, V> map = hashtable[hash(key)];
        if (map.containsKey(key)) &#123;
            map.put(key, val);
        &#125; else &#123;
            map.put(key, val);
            size++;
            if (size >= UpperTol * M)
                resize(M * 2);
        &#125;
    &#125;

    public V remove(K key) &#123;
        V ret = null;
        TreeMap&lt;K, V> map = hashtable[hash(key)];
        if (map.containsKey(key)) &#123;
            ret = map.remove(key);
            size--;
            if (size &lt;= LowerTol * M &amp;&amp; M > initCapacity)
                resize(M / 2);
        &#125;
        return ret;

    &#125;

    public void set(K key, V val) &#123;
        TreeMap&lt;K, V> map = hashtable[hash(key)];
        if (!map.containsKey(key))
            throw new IllegalArgumentException(key + "不存在。");
        map.put(key, val);
    &#125;

    public boolean contains(K key) &#123;
        return hashtable[hash(key)].containsKey(key);
    &#125;

    public V get(K key) &#123;
        return hashtable[hash(key)].get(key);
    &#125;

    private void resize(int capacity) &#123;
        TreeMap&lt;K, V>[] newHashtable = new TreeMap[capacity];
        for (int i = 0; i &lt; capacity; i++) &#123;
            newHashtable[i] = new TreeMap&lt;>();
        &#125;
        int oldM = M;
        this.M = capacity;
        for (int i = 0; i &lt; oldM; i++) &#123;
            for (K key : hashtable[i].keySet()) &#123;
                newHashtable[hash(key)].put(key, hashtable[i].get(key));
            &#125;
        &#125;
        this.hashtable = newHashtable;
    &#125;
&#125;
